import{loadTasks}from"./addItem";export function tasksCheckbox(t){let e=t.target.checked;console.log(e);let a=JSON.parse(localStorage.getItem("tasks"))||[],o=t.target.closest(".table__tasks-item");if(!o)return;let l=o.getAttribute("data-id")?parseInt(o.getAttribute("data-id")):0;for(let t=0;t<a.length;t++)a[t].id===l&&(a[t].completed=e,localStorage.setItem("tasks",JSON.stringify(a)),loadTasks("completed",localStorage.getItem("filter")),window.location.reload())}